esqlQuery.esql:
FROM metrics-kubeletstatsreceiver.otel-*
| WHERE k8s.node.cpu.usage IS NOT NULL
| STATS avg_cpu = AVG(k8s.node.cpu.usage)
    BY k8s.node.name
// Threshold in CPU cores — set to ~90% of your node's allocatable CPU.
// Example: for a 4-core node with allocatable_cpu = 3.8, use 3.6.
// For an 8-core node, use ~7.2. Adjust per your cluster sizing.
| EVAL cpu_threshold = 3.6
| WHERE avg_cpu > cpu_threshold
| KEEP k8s.node.name, avg_cpu, cpu_threshold
